import org.slf4j.MDC;
import jakarta.servlet.*;
import jakarta.servlet.http.*;
import org.springframework.core.annotation.Order;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;
import java.io.*;
import java.util.UUID;

@Component @Order(1)
public class RazorpayLoggingFilter extends OncePerRequestFilter {
    @Override protected void doFilterInternal(
            HttpServletRequest req, HttpServletResponse res, FilterChain chain)
            throws ServletException, IOException {
        String requestId  = req.getHeader('X-Request-Id');
        if (requestId == null) requestId = UUID.randomUUID().toString().substring(0,8);
        String userId     = req.getHeader('X-User-Id');
        String merchantId = req.getHeader('X-Merchant-Id');

        MDC.put('requestId',  requestId);
        MDC.put('userId',     userId     != null ? userId     : 'anonymous');
        MDC.put('merchantId', merchantId != null ? merchantId : 'unknown');
        MDC.put('path',       req.getRequestURI());
        MDC.put('method',     req.getMethod());

        long start = System.currentTimeMillis();
        try {
            chain.doFilter(req, res);
        } finally {
            MDC.put('durationMs', String.valueOf(System.currentTimeMillis() - start));
            MDC.put('status', String.valueOf(res.getStatus()));
            MDC.clear();  // CRITICAL: prevents context leak to next request
            // WITHOUT clear: thread pool reuses this thread for next request
            // → next request logs show USR-001's merchantId, path, requestId
            // → monitoring: wrong merchant sees activity that isn't theirs
        }
    }
}

