        assertTrue(logEvent.getFormattedMessage().contains('Visa declined'));
    }
}

// Loki LogQL queries for Razorpay structured JSON logs:

// 1. All ERROR logs for payment-service:
// {app='payment-service', level='ERROR'}
// → filters by label (fast) + level field in JSON log

// 2. All slow payments (latencyMs > 1000ms):
// {app='payment-service'} | json | durationMs > 1000
// → json filter: parses JSON log line into fields
// → durationMs > 1000: numeric filter on parsed field

// 3. All logs for a specific traceId (cross-service):
// {namespace='razorpay'} |= 'abc123def456'
// → searches across ALL services for the traceId string
// Refine: {namespace='razorpay'} | json | traceId='abc123def456'

// 4. Error rate for Visa gateway (last 5 min):
// rate({app='payment-service'} | json | gateway='visa' | level='ERROR' [5m])
// → rate(): errors per second in 5-minute rolling window
// → use in Grafana panel as error rate metric

// 5. All logs for specific merchant:
// {app='payment-service'} | json | merchantId='MRC-123'
// → requires merchantId field in structured JSON log (from MDC!)
// → why MDC matters: without MDC, would need grep across all services

public class LokiQueryExamples {
    public static void main(String[] a) {
        System.out.println("Loki: query structured logs like a database");
        System.out.println("{app='x'} | json | field > value");
    }
}

