import org.slf4j.MDC;
import java.util.*;
import java.util.concurrent.CompletableFuture;
import org.springframework.stereotype.Service;

@Service
public class AsyncMDCService {

    public CompletableFuture<String> sendNotificationAsync(String userId) {
        // Capture MDC BEFORE going async (while still in request thread):
        Map<String, String> mdcContext = MDC.getCopyOfContextMap();
        if (mdcContext == null) mdcContext = new HashMap<>();
        final Map<String, String> finalMdc = mdcContext;

        return CompletableFuture.supplyAsync(() -> {
            // Restore MDC in async thread:
            MDC.setContextMap(finalMdc);
            try {
                // Now: requestId, userId, traceId all available in this thread's logs!
                LoggerFactory.getLogger(AsyncMDCService.class)
                    .info('Sending notification userId={}', userId);
                return 'SENT';
            } finally {
                MDC.clear();  // Clear in async thread too!
            }
        });
    }

    // WITHOUT this pattern:
    // Async thread has empty MDC → logs show no userId, no requestId, no traceId
    // Log correlation becomes impossible for async operations
    //
    // WITH this pattern:
    // Async thread logs include the same requestId as the request thread
    // All notifications linkable to the original request in Loki

    public static void main(String[] a) {
        System.out.println("MDC copy to async: getCopyOfContextMap() → setContextMap() in async thread");
    }
}

