// BAD: Never log sensitive data

// ❌ Card number:
// log.info('Charging card {}', cardNumber);
// → logs full card number: '4111111111111111' in plaintext
// → any log access = full card exposure = PCI-DSS violation
// ✅ CORRECT: log only the last 4 digits
public class SecureLogging {
    void logCardAction(String cardNumber, String action) {
        String masked = '****' + cardNumber.substring(cardNumber.length()-4);
        log.info('Card action={} card={}', action, masked);
    }

    // ❌ API key:
    // log.debug('Using API key {}', apiKey);
    // → logs 'rzp_live_secretkey123456' — full compromise if logs leaked
    // ✅ CORRECT: log only first 8 chars (non-sensitive prefix):
    void logApiUsage(String apiKey) {
        String safe = apiKey.substring(0, Math.min(8, apiKey.length())) + '...';
        log.debug('API request key={}', safe);
    }

    // ❌ Request body with PAN:
    // log.debug('Request: {}', requestBody.toString());
    // → may contain PAN, CVV, address
    // ✅ CORRECT: log only non-sensitive fields:
    void logPaymentRequest(String merchantId, String gateway, double amount) {
        log.info('Payment request merchantId={} gateway={} amount={}',
            merchantId, gateway, amount);
        // NO card details, NO PAN, NO CVV
    }

    // ❌ Password:
    // log.info('Authenticating user={} password={}', username, password);
    // ✅ CORRECT: never log passwords — not even hashed
    void logAuthAttempt(String username) {
        log.info('Auth attempt username={}', username);
        // No password, no hash — compliance requires this
    }

    private static final org.slf4j.Logger log = org.slf4j.LoggerFactory.getLogger(SecureLogging.class);
}

