// Grafana Loki alert rules for Razorpay:

// 1. Payment error rate > 1% in 5 minutes:
// LogQL: sum(rate({app='payment-service', level='ERROR'} [5m]))
//      / sum(rate({app='payment-service'} [5m])) > 0.01
// → ratio: error log rate / total log rate > 1%
// → fires every 5 minutes if condition met
// → compare with Prometheus metric alert: rate(payments_total{status='failure'} [5m]) > 0.01
//   both should fire together — if only one fires: investigate log vs metric discrepancy

// 2. Order execution errors (SEBI critical):
// {app='order-service', level='ERROR'} |= 'order.rejected'
// → ANY error log mentioning 'order.rejected' triggers immediate alert
// → no rate threshold: ANY occurrence is noteworthy for SEBI compliance
// → alert channels: Slack #trading-alerts + PagerDuty

// 3. MDC context leak detection:
// {app='payment-service'} | json | userId='USR-001' | requestId!='REQ-from-USR-001'
// This is hard to detect automatically — better: unit test MDC.clear() in filter
// Manual check: if userId appears in paths that don't belong to that user

// 4. Loki vs Prometheus alerts — COMPLEMENT each other:
// Prometheus metric alert:
//   rate(payments_processed_total{status='failure'}[5m]) / rate(payments_processed_total[5m]) > 0.01
//   → fires on high-level error rate
// Loki alert:
//   {app='payments', level='ERROR'} |= 'Visa declined'
//   → fires on specific error type, with full log context
// Together: Prometheus tells WHAT (error rate), Loki tells WHY (specific error message)

public class LokiAlertPatterns {
    public static void main(String[] a) {
        System.out.println("Prometheus: aggregate metric alerts (error rate > threshold)");
        System.out.println("Loki: log-pattern alerts (specific error text, specific user)");
        System.out.println("Together: complete picture of production health");
    }
}

import io.micrometer.core.instrument.*;
import io.micrometer.tracing.Tracer;
import io.micrometer.tracing.Span;
import org.slf4j.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import ch.qos.logback.classic.spi.ILoggingEvent;
import ch.qos.logback.core.read.ListAppender;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@Service
class ThreePillarPaymentService {
    private static final Logger log=LoggerFactory.getLogger(ThreePillarPaymentService.class);
    private final MeterRegistry reg;
    private final Tracer tracer;
    private final Timer timer;

    ThreePillarPaymentService(MeterRegistry r,Tracer t){
        reg=r;tracer=t;
        timer=Timer.builder('three.pillar.payment').publishPercentiles(0.5,0.95,0.99).register(reg);
    }

    String process(String gateway,double amount){
        return timer.record(()->{
            Span s=tracer.nextSpan().name('payment.process');
            try(var ws=tracer.withSpan(s.start())){
                s.tag('gateway',gateway).tag('amount',String.valueOf(amount));
                MDC.put('gateway',gateway);
                log.info('payment.start gateway={} amount={}',gateway,amount);
                try{Thread.sleep(50);}catch(InterruptedException e){Thread.currentThread().interrupt();}
                String id='PAY-'+System.currentTimeMillis();
                reg.counter('three.pillar.payments','status','success','gateway',gateway).increment();
                s.tag('paymentId',id);
                log.info('payment.complete paymentId={} gateway={} amount={}',id,gateway,amount);
                return id;
            }finally{s.end();MDC.remove('gateway');}
        });
    }
}

@SpringBootTest
class ThreePillarTest{
    @Autowired ThreePillarPaymentService svc;
    @Autowired MeterRegistry reg;
    @Autowired Tracer tracer;
    ch.qos.logback.classic.Logger l=(ch.qos.logback.classic.Logger)LoggerFactory.getLogger(ThreePillarPaymentService.class);
    ListAppender<ILoggingEvent> appender=new ListAppender<>();
    @BeforeEach void s(){appender.start();l.addAppender(appender);}
    @AfterEach  void c(){l.detachAppender(appender);appender.stop();appender.list.clear();}
    @Test void metrics_work(){svc.process('visa',999.0);assertNotNull(reg.find('three.pillar.payment').timer());assertTrue(reg.find('three.pillar.payment').timer().count()>=1);}
    @Test void logs_generated(){svc.process('mastercard',499.0);assertFalse(appender.list.isEmpty());assertTrue(appender.list.stream().anyMatch(e->e.getFormattedMessage().contains('payment.start')));}
    @Test void tracer_available(){assertNotNull(tracer);assertDoesNotThrow(()->svc.process('upi',99.0));}
}
